SELECT metric_name, metric_value
FROM campaign_metrics
WHERE metric_name IN ('open rate', 'click-through rate');

SELECT changed_on
FROM preferences_history
ORDER BY changed_on DESC;

SELECT channel_id, COUNT(*)
FROM campaign_channel
GROUP BY channel_id;

SELECT AVG(f.rating) AS avg_rating
FROM feedback f
WHERE f.customer_id NOT IN (
    SELECT customer_id FROM feedback
);

SELECT COUNT(*) AS total_preferences_history 
FROM preferences_history 
WHERE changed_on > '2020-01-01';

SELECT customer_id, COUNT(preference_id) as num_preferences
FROM preferences
GROUP BY customer_id;
